from langchain.schema import AIMessage, ToolMessage

def detect_tool_loops(memory_messages, max_repeats: int = 3) -> bool:
    tool_calls = []
    for msg in memory_messages[-20:]:  # Last 20 messages
        if isinstance(msg, AIMessage) and msg.tool_calls:
            for tc in msg.tool_calls:
                tool_calls.append((tc['name'], tc['args']))

    from collections import Counter
    call_counts = Counter(tool_calls)
    return any(count >= max_repeats for count in call_counts.values())

# Usage
if detect_tool_loops(memory.chat_memory.messages):
    print('🔄 Tool call loop detected!')

