from langchain.agents import AgentExecutor
from langchain.memory import ConversationBufferMemory

class LoopSafeAgentExecutor(AgentExecutor):
    def _take_next_step(self, *args, **kwargs):
        recent_calls = self.agent.memory.chat_memory.messages[-5:]
        if self.detect_loop(recent_calls):
            return {'output': 'Breaking potential tool loop'}
        return super()._take_next_step(*args, **kwargs)

    def detect_loop(self, messages):
        tool_names = [m.tool_calls[0]['name'] for m in messages[-3:] 
                     if hasattr(m, 'tool_calls') and m.tool_calls]
        return len(set(tool_names)) == 1 and len(tool_names) >= 3

# Usage
executor = LoopSafeAgentExecutor.from_agent_and_tools(...)
